-- Enrichment marathon batch: Cacher, Cacoo, Cadence Design Systems, Cairo-Dock, Caja, calcurse, Calendar Icons Generator, Calendarific

-- ── Cacher ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Cacher is a cloud-based code snippet manager built for professional developers and engineering teams who need a fast, searchable home for reusable code. Launched in 2017 by a small SaaS team based in Boston, Massachusetts, Cacher lets individuals and teams create, organize, and share snippets across almost any programming language, then surface them instantly inside the editors and terminals they already use through native plugins for Visual Studio Code and IntelliJ-based IDEs, a browser extension, a Raycast integration, and a command-line interface. Snippets can be grouped into private or public libraries, tagged with labels, attached to files, and synced with GitHub Gists for teams that already lean on Git-based workflows. In August 2025 Cacher was acquired by Starr Holding Company, which has committed to keeping the product running under its existing brand while investing in further development, so the tool remains actively maintained rather than winding down. For teams tired of pasting the same boilerplate into Slack threads or losing snippets in scattered gists, Cacher centralizes that knowledge in one searchable, permissioned library.$q$, short_description),
  pricing_model = COALESCE($q$Freemium subscription with paid Expert and Teams tiers, plus a self-hosted enterprise option$q$, pricing_model),
  starting_price = COALESCE($q$Free; paid plans start at $9.99/month (Expert, billed annually)$q$, starting_price),
  founded_year = COALESCE(2017, founded_year),
  company_size = COALESCE($q$1-10$q$, company_size),
  headquarters = COALESCE($q$Boston, Massachusetts, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Cacher Review 2026: Pricing, Features and Is It Still Active$q$, seo_title),
  seo_meta_description = COALESCE($q$Cacher is a code snippet manager for developers and teams. See 2026 pricing, IDE integrations, pros and cons, and its acquisition by Starr Holding Company.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Cacher is a code snippet management platform aimed at professional developers who accumulate reusable pieces of code, configuration, and scripts across projects and want a single organized, searchable place to keep them. The product launched on September 5, 2017 out of Boston, Massachusetts, and grew as a small, independently run SaaS business before being acquired by Starr Holding Company in August 2025. Starr has stated Cacher will continue operating under its existing brand while receiving new investment in engineering and marketing, which means the tool is actively maintained in 2026 rather than being sunset, an important distinction in a category where several competing snippet managers have shut down or stalled over the years. At its core, Cacher organizes code into snippets that can contain multiple files, syntax highlighting for dozens of languages, and descriptive labels for filtering. Snippets can be kept fully private, shared publicly on the snippets.cacher.io gallery, or shared within a team library with role-based access. What differentiates Cacher from a plain notes app or a folder of gists is its integration surface: dedicated plugins for Visual Studio Code and IntelliJ-based IDEs let developers insert snippets without leaving the editor, a browser extension brings the library to any web page, a Raycast integration serves power users on macOS, and a command-line interface lets snippets be scripted into build tools or dotfiles. Teams that already maintain code on GitHub can import and sync Gists directly into Cacher rather than re-entering everything by hand. Pricing follows a straightforward three-tier freemium model. The Free plan supports 15 private snippets and 3 private labels with unlimited public snippets, which is enough for a solo developer experimenting with the tool or maintaining a small public library. The Expert plan, at $9.99 per month when billed annually, removes those private caps entirely, adds the IDE plugins, and enables an ad-free Quick Create workflow, making it the natural upgrade for any individual developer who relies on Cacher daily. The Teams plan starts at $29.99 per month for the first five seats (billed annually, with additional seats at $8 per month) and adds shared team libraries, lightweight code review threads, activity notifications, and role management, with SSO available for larger teams or as a paid add-on for smaller ones. Organizations with strict data-residency or compliance requirements can license a self-hosted deployment for $5,000 per year plus $150 per seat per year. Overall, Cacher fits a specific niche: teams and individuals who want a dedicated, IDE-integrated snippet library rather than repurposing a general note-taking app, wiki, or their own private GitHub Gists.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '90df5fe5-078a-4b5b-9d71-b1f5c26dc331';

