-- ── Cacoo ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Cacoo is a browser-based diagramming and flowchart tool made by Nulab Inc., the Fukuoka, Japan-based software company also known for the Backlog project management platform and the Typetalk team chat app. Released in 2010, Cacoo lets individuals and teams draw flowcharts, wireframes, network diagrams, mind maps, org charts, entity-relationship diagrams, and UML models in real time, with multiple people able to edit the same canvas simultaneously and watch each other's cursors move live. Because it runs entirely in the browser, Cacoo requires no desktop installation and works across Mac, Windows, and Linux, with editing also embeddable inside Google Workspace, Confluence, and other tools via official integrations. A free plan covers up to six diagram sheets for unlimited users, making Cacoo an easy way for small teams to try real-time collaborative diagramming before committing to a paid Pro or Team subscription. Because Cacoo comes from the same company behind Backlog, teams already using Nulab's project management suite can adopt it with a shared login and consistent design language, making it a natural fit for product, engineering, and design teams already inside the Nulab ecosystem.$q$, short_description),
  pricing_model = COALESCE($q$Freemium subscription, priced per user per month with an unlimited-user free tier$q$, pricing_model),
  starting_price = COALESCE($q$Free; paid plans start at $6/user/month$q$, starting_price),
  founded_year = COALESCE(2010, founded_year),
  company_size = COALESCE($q$51-200$q$, company_size),
  headquarters = COALESCE($q$Fukuoka, Japan (Nulab Inc.)$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$Japanese$q$]::text[],
  seo_title = COALESCE($q$Cacoo Review 2026: Nulab's Real-Time Diagramming Tool and Pricing$q$, seo_title),
  seo_meta_description = COALESCE($q$Cacoo is Nulab's real-time online diagramming tool for flowcharts, wireframes, and mind maps. See 2026 pricing, features, pros, cons and how it fits with Backlog.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Cacoo is an online diagramming and visual collaboration tool built by Nulab Inc., a Japanese software company founded in 2004 and headquartered in Fukuoka, with additional offices including Tokyo, Kyoto, New York, Amsterdam, and Singapore. Nulab is best known in Western markets for Backlog, its project management and issue-tracking tool, and Cacoo is the company's entry into visual collaboration, first released in 2010. The core idea behind Cacoo is real-time, multiplayer diagramming in the browser: several people can open the same flowchart, wireframe, network diagram, mind map, organizational chart, entity-relationship diagram, or UML model at once, see each other's cursors and edits live, and communicate through built-in video chat and comment threads without leaving the canvas. Because everything runs in a web browser rather than a native desktop application, Cacoo works identically on Mac, Windows, and Linux, and diagrams can be embedded into Confluence, Google Workspace documents, and other third-party tools through official integrations. Cacoo ships with a sizable library of templates and shape stencils spanning software architecture, network topology, floor plans, and standard flowchart symbols, along with a code-to-diagram feature that can generate certain diagram types from structured input, revision history so teams can roll back changes, and a lightweight built-in Kanban tool for basic task tracking alongside diagrams. Pricing follows a tiered subscription model typical of SaaS diagramming tools. The Free plan is genuinely free indefinitely, supports unlimited users, and includes six diagram sheets, templates and shapes, PNG export, real-time editing, in-app video chat, and comment threads, which is enough for a small team or an individual evaluating the tool. The Pro plan, at $6 per user per month (with roughly 17 percent savings on annual billing), removes the sheet cap, adds unlimited sheets, multiple export formats, revision history, and premium templates. The Team plan, also listed at $6 per user per month, builds on Pro with support for larger organizations of up to 1,000 users, one-on-one onboarding training, and password-protected diagrams. An Enterprise plan is available on custom pricing for organizations that need SAML single sign-on, SCIM user provisioning, audit logs, and centralized access management. A 14-day free trial is available on any paid plan without requiring a credit card. For teams already using Nulab's Backlog for project tracking, Cacoo's shared login and consistent design language make it a low-friction way to add diagramming into the same workflow, which is one of its more distinctive selling points compared with diagramming tools built by unrelated vendors.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '7a80a5e8-cb8b-4a90-830c-9ea5c7c7d5fc';

