-- ── Cairo-Dock ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Cairo-Dock is a free, open-source application launcher and dock for Linux desktops, designed to give users a customizable, animated bar of application icons similar in spirit to the docks found on macOS, but fully skinnable and desktop-environment-agnostic. Originally created by developer Fabrice Rey (known online as Fabounet) and first released in the mid-2000s (commonly dated to around 2007), Cairo-Dock is written in C and rendered using the Cairo graphics library combined with OpenGL, which lets it apply hardware-accelerated animations, reflections, and zoom effects while staying light on CPU usage. It is distributed under the GNU General Public License version 3, meaning the source code is freely available and the project is maintained by a small community of volunteer contributors on GitHub under the Cairo-Dock organization rather than by a commercial company. The dock works alongside virtually any Linux desktop environment (GNOME, KDE, Xfce, and others), supports a large catalog of downloadable themes and applets covering things like a clock, weather, system tray, Wi-Fi status, and email notifications, and can be detached into individual desktop widgets. Version 3.6 brought full Wayland support and HiDPI-aware rendering, keeping the project relevant as Linux distributions have shifted away from the older X11 display server.$q$, short_description),
  pricing_model = COALESCE($q$Free and open-source software; no paid tiers$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2007, founded_year),
  company_size = COALESCE($q$Open-source community project (volunteer-maintained)$q$, company_size),
  headquarters = COALESCE($q$N/A - community-maintained open-source project$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$French$q$, $q$German$q$, $q$Spanish$q$, $q$Italian$q$, $q$and other community-translated languages$q$]::text[],
  seo_title = COALESCE($q$Cairo-Dock: Free Customizable Linux Dock and App Launcher$q$, seo_title),
  seo_meta_description = COALESCE($q$Cairo-Dock is a free, open-source, GPU-accelerated application dock for Linux. See its features, themes, Wayland support, and how it compares to other launchers.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Cairo-Dock is a free and open-source application launcher and dock for Linux desktop environments, built to give users a macOS-style animated icon bar that is heavily customizable rather than tied to any single desktop environment's visual style. The project was created by developer Fabrice Rey, who goes by Fabounet in the open-source community, and dates back to the mid-2000s, with the project commonly cited as originating around 2007 before iterating through many major and minor releases over nearly two decades. It is written primarily in C and uses the Cairo 2D graphics library together with OpenGL for rendering, which allows it to apply hardware-accelerated visual effects such as zoom-on-hover, reflections, and smooth animations while keeping CPU usage low, an important design goal for a piece of software that runs continuously in the background of a desktop session. Cairo-Dock is licensed under the GNU General Public License version 3, and its source code is maintained publicly on GitHub under the Cairo-Dock organization, with the broader community and documentation hosted at glx-dock.org. Because it has no corporate owner, there is no roadmap driven by commercial incentives; development pace has varied over the years depending on volunteer contributor availability, which is a normal characteristic of long-running open-source desktop projects. Functionally, Cairo-Dock acts as both a taskbar and an application launcher, arranging icons for pinned and running applications into one or more docks that can be positioned anywhere on screen and configured with different animation styles, icon sizes, and hide behaviors. What sets it apart from simpler launchers is its extensibility: a large catalog of applets can be added to the dock or detached to run as standalone desktop widgets, covering things like a clock, weather forecasts, a system tray, Wi-Fi and network status, an email notifier, and various visual effects add-ons. Dozens of ready-made themes are downloadable directly from within the application, letting users change the dock's entire look in a couple of clicks, and power users can go further with granular manual configuration of colors, transparency, icon behavior, and layout. A major milestone came with version 3.6, which added full support for the Wayland display protocol alongside the traditional X11 support Cairo-Dock has had since its inception, plus HiDPI-aware rendering so icons, fonts, and dock elements stay sharp on high-resolution 4K and higher displays. This Wayland work matters because most major Linux distributions have been defaulting to Wayland sessions in recent years, and desktop utilities that fail to add Wayland support risk becoming unusable for a growing share of users; Cairo-Dock's continued compatibility work is one of the clearer signs the project remains actively maintained rather than abandoned. Being free, open-source, and desktop-environment-agnostic, Cairo-Dock is typically installed by Linux users who want a more visually customizable alternative to their distribution's default taskbar, particularly on lightweight desktop environments like Xfce or on window-manager-only setups that lack a polished built-in launcher.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'ff837062-8532-4654-b1dc-94c79abddc79';

