-- ── calcurse ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$calcurse is a free, open-source, text-based calendar and scheduling application built for the terminal on Unix-like systems including Linux, macOS, BSD variants, and other Unix derivatives. It was created in 2004 by Frederic Culot, who began developing it while finishing his PhD in astrophysics as a personal tool for keeping track of appointments and to-do items, and its name is a portmanteau of calendar and ncurses, the terminal UI library it is built on. Culot released calcurse under the permissive BSD license, and since 2011 the project has been maintained by Lukas Fleischer, with many core features added since 2017 designed and implemented by contributor Lars Henriksen. The application splits its terminal interface into three panels, a monthly calendar view, a list of appointments for the selected day, and a to-do list, all navigable with configurable, largely vi-style keyboard shortcuts. It supports recurring and all-day events, attached notes opened in the user's preferred external text editor, a configurable notification system for upcoming deadlines, import and export in the standard iCalendar format, and experimental CalDAV support for syncing with mobile devices and other calendar services. Because it runs entirely inside a terminal with no graphical dependencies, calcurse is popular among developers and sysadmins who live in the command line and want scheduling that fits into scriptable, keyboard-driven workflows rather than switching to a separate graphical calendar app.$q$, short_description),
  pricing_model = COALESCE($q$Free and open-source software; no paid tiers$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2004, founded_year),
  company_size = COALESCE($q$Open-source community project (volunteer-maintained)$q$, company_size),
  headquarters = COALESCE($q$N/A - community-maintained open-source project$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$French$q$, $q$German$q$, $q$Dutch$q$, $q$Spanish$q$, $q$Italian$q$]::text[],
  seo_title = COALESCE($q$calcurse: The Free Terminal-Based Calendar and To-Do App for Unix$q$, seo_title),
  seo_meta_description = COALESCE($q$calcurse is a free, open-source, keyboard-driven calendar and task manager for the terminal. Learn its history, features, and how it compares to graphical calendars.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$calcurse is a text-based calendar, scheduling, and to-do list application designed to run entirely inside a terminal on Unix-like operating systems, including Linux, macOS, and the BSD family (OpenBSD, FreeBSD, and NetBSD). It was created in 2004 by Frederic Culot, a developer who was finishing his PhD in astrophysics at the time and built the tool originally for his own use to manage an increasingly complicated schedule of appointments and tasks, before releasing it publicly under the permissive BSD license. The name calcurse combines calendar with ncurses, the terminal-based user interface library the application is built on, which is a fitting description of what the software actually is: a full calendar and task manager that never requires leaving the command line or opening a graphical window. Culot maintained the project in its early years, and since 2011 primary maintenance has been carried on by Lukas Fleischer, with numerous core features added from 2017 onward designed and implemented by contributor Lars Henriksen, reflecting the kind of small, dedicated volunteer maintainer team typical of long-lived Unix command-line utilities. The interface is organized into three panels visible at once: a monthly calendar grid in one corner, a list of the current day's scheduled appointments in another, and a to-do list at the bottom for tracking tasks that aren't tied to a specific time. Navigation uses configurable keyboard shortcuts that default to a scheme familiar to vi and vim users, letting experienced terminal users move through days, add events, and check off tasks without touching a mouse. Functionally, calcurse supports both one-off and recurring appointments, all-day events, and the ability to attach freeform notes to any calendar item, which open in the user's preferred external text editor rather than a built-in note field. A configurable notification system can alert users to upcoming deadlines and appointments, which is particularly useful given the software has no persistent graphical presence to glance at. For interoperability, calcurse can import and export calendar data in the standard iCalendar (.ics) format used by virtually every mainstream calendar application, and it includes experimental CalDAV support, letting it synchronize with mobile devices and CalDAV-compatible calendar servers rather than existing as a fully isolated island of data. calcurse also supports command-line-only, non-interactive operation, meaning its data can be filtered, formatted, and queried through command-line flags, making it scriptable for use in shell scripts, status bars, or automated reminder systems rather than only through its interactive curses interface. calcurse's target audience is narrow but well-defined: developers, system administrators, and other terminal-centric users who prefer to manage their schedule without leaving a terminal multiplexer session, and who value calcurse's minimal resource footprint, scriptability, and plain-text-adjacent data storage over the visual polish of a graphical or web-based calendar application.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '3a56e0bb-0bcb-44be-944e-9e4b11bb4539';

